const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();
  
  // 设置viewport
  await page.setViewportSize({ width: 1280, height: 900 });
  
  try {
    console.log('正在访问页面...');
    await page.goto('https://www.whhnhy.com:37777/axure/yaoqingma/?id=33ie1g&p=%E5%86%85%E6%B5%8B%E9%82%80%E8%AF%B7', {
      waitUntil: 'networkidle',
      timeout: 30000
    });
    
    // 等待iframe加载
    await page.waitForTimeout(3000);
    
    // 获取页面内容
    const title = await page.title();
    console.log('页面标题:', title);
    
    // 尝试获取iframe内的内容
    const frames = page.frames();
    console.log('iframe数量:', frames.length);
    
    // 获取所有文本内容
    const bodyText = await page.evaluate(() => {
      return document.body.innerText;
    });
    console.log('页面文本内容:');
    console.log(bodyText);
    
    // 获取页面截图
    await page.screenshot({ path: '/root/.openclaw/workspace/test_cases/yaoqingma.png', fullPage: false });
    console.log('截图已保存到 /root/.openclaw/workspace/test_cases/yaoqingma.png');
    
    // 尝试获取iframe内容
    for (let i = 0; i < frames.length; i++) {
      const frame = frames[i];
      try {
        const frameUrl = frame.url();
        console.log(`Frame ${i} URL:`, frameUrl);
        const frameText = await frame.evaluate(() => document.body.innerText).catch(() => '无法获取');
        console.log(`Frame ${i} 文本:`, frameText);
      } catch (e) {
        console.log(`Frame ${i} 错误:`, e.message);
      }
    }
    
  } catch (error) {
    console.error('错误:', error.message);
  }
  
  await browser.close();
})();
